// 1️⃣ Función de limpieza total
const clean = (s) => (s || "").toString().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, "");

// 2️⃣ Recuperamos los datos del Excel (usamos .first() para evitar errores de emparejamiento)
const excelRows = $("Agrupar Excel").first().json.excel_data;

// 3️⃣ Función de búsqueda inteligente
const findTeam = (name) => {
  if (!name) return null;
  const n = clean(name);

  let found = excelRows.find(row => clean(row.Equipo) === n);
  if (found) return found;

  return excelRows.find(row => {
    const e = clean(row.Equipo);
    if (e.length < 3) return false;

    const conflicts = [
      { city: "madrid", keys: ["real", "atletico", "rayo"] },
      { city: "manchester", keys: ["city", "united"] },
      { city: "milan", keys: ["inter", "ac"] },
      { city: "sevilla", keys: ["betis", "sevilla"] },
      { city: "liverpool", keys: ["everton", "liverpool"] },
      { city: "london", keys: ["arsenal", "chelsea", "tottenham", "west", "crystal", "fulham", "brentford"] }
    ];

    for (const conflict of conflicts) {
      if (n.includes(conflict.city) && e.includes(conflict.city)) {
        return conflict.keys.some(key => n.includes(key) && e.includes(key));
      }
    }
    return n.includes(e) || e.includes(n);
  });
};

// 4️⃣ Procesamos el item actual
const matchData = $json;
const homeRow = findTeam(matchData.home);
const awayRow = findTeam(matchData.away);

const homePos = parseInt(homeRow?.Pos || homeRow?.posicion) || 12;
const awayPos = parseInt(awayRow?.Pos || awayRow?.posicion) || 12;
const posDiff = Math.abs(homePos - awayPos);

return {
  json: {
    ...matchData,
    home_pos: homePos,
    away_pos: awayPos,
    pos_diff: posDiff,
    interest_score: (posDiff >= 8 ? 40 : 0) + (homePos <= 6 || awayPos <= 6 ? 30 : 0),
    home_stats: homeRow || {},
    away_stats: awayRow || {}
  }
};

const results = [];
// Intentamos buscar el nodo de Excel. Si falla, el catch nos avisará.
let originalData = [];
try {
  originalData = $("Cruzar con Excel").all();
} catch (e) {
  // Si tu nodo se llama distinto, poné el nombre exacto aquí abajo:
  originalData = $("Cruzar con Excel").all(); 
}

const clean = (s) => (s || "").toString().toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]/g, "");

for (const item of $input.all()) {
    const raw = item.json?.text ?? item.json?.content?.parts?.[0]?.text ?? "";
    let parsed = {};

    try {
        const start = raw.indexOf('{');
        const end = raw.lastIndexOf('}');
        if (start === -1 || end === -1) throw new Error("No JSON found");
        parsed = JSON.parse(raw.substring(start, end + 1));

        const homePick = clean(parsed.home || parsed.match || "");

        // 🧠 Búsqueda ultra-segura
        const matchedNode = originalData.find(o => {
            const oHome = clean(o.json.home || "");
            const oMatch = clean(o.json.match || "");
            return (homePick.includes(oHome) && oHome.length > 3) || (oMatch.includes(homePick));
        });

        const orig = matchedNode ? matchedNode.json : {};

        // 🛡️ NORMALIZACIÓN TOTAL (Aquí evitamos el undefined)
        const output = {
            ...orig,        // Trae stats e interest_score de Excel
            ...parsed,      // Trae razonamiento y selección de la IA
            stake: parsed.stake || parsed.stake_recomendado || orig.stake || 1,
            confianza: parsed.confianza || parsed.nivel_confianza || orig.confianza || 70,
            interest_score: orig.interest_score || parsed.interest_score || 0,
            _valid: true
        };

        results.push({ json: output });

    } catch(e) {
        results.push({ json: { _valid: false, _error: e.message, raw_text: raw } });
    }
}
return results;

const p = $json;

// 🌍 1. TRADUCTOR DE MERCADOS "ESTÁNDAR PRO"
let mercadoRaw = (p.mercado || "").toString().toLowerCase();
let seleccionRaw = (p.seleccion || "").toString().toLowerCase();
let mercadoEs = p.mercado || "Mercado Desconocido";

if (mercadoRaw.includes('both teams') || mercadoRaw.includes('btts')) {
    mercadoEs = 'Ambos Marcan (BTTS)';
} 
else if (mercadoRaw.includes('spread') || mercadoRaw.includes('asian') || seleccionRaw.includes('.25') || seleccionRaw.includes('.75')) {
    mercadoEs = 'Hándicap Asiático';
} 
else if (mercadoRaw.includes('handicap')) {
    mercadoEs = 'Hándicap Europeo (3-Way)';
}
else if (mercadoRaw.includes('totals') || mercadoRaw.includes('over') || mercadoRaw.includes('under')) {
    mercadoEs = 'Goles Totales (O/U)';
}
else if (mercadoRaw.includes('ml') || mercadoRaw.includes('money line') || mercadoRaw.includes('result') || mercadoRaw.includes('1x2')) {
    mercadoEs = 'Resultado Final (1X2)';
}
else if (mercadoRaw.includes('draw no bet') || mercadoRaw.includes('dnb')) {
    mercadoEs = 'Empate no Válido (DNB)';
}

// 🌍 2. TRADUCTOR DE SELECCIONES
let seleccionEs = (p.seleccion || '')
    .toString()
    .replace(/yes/gi, 'Sí').replace(/no/gi, 'No')
    .replace(/home/gi, 'Local').replace(/away/gi, 'Visitante').replace(/draw/gi, 'Empate')
    .replace(/over/gi, 'Más de').replace(/under/gi, 'Menos de');

// 🔢 3. CÁLCULOS DE DISEÑO (Barra, Estrellas, Cuota)
const numConfianza = parseInt(p.confianza) || 70;
const numStake = parseInt(p.stake) || 1;
const cuota = parseFloat(p.cuota_objetivo || p.cuota) || 0;
const stars = "⭐".repeat(Math.min(5, Math.ceil(numStake)));
const barLen = Math.round(numConfianza / 10);
const bar = "🟦".repeat(Math.max(0, barLen)) + "⬜".repeat(Math.max(0, 10 - barLen));

// 📊 4. ESTADÍSTICAS (Contrato Directo con la IA)
const l = p.stats_local || p.stats?.local || p.home_stats || {};
const v = p.stats_visitante || p.stats?.visitante || p.away_stats || {};

// 📝 5. CONSTRUCCIÓN DEL MENSAJE FINAL
const msg = [
    `🌍 *PARTIDO*`,
    `🏆 *${p.competition || p.league || 'Fútbol'}*`,
    `🤝 ${p.match || (p.home + ' vs ' + p.away)}`,
    `📅 ${p.date ? p.date.split('T')[0] : ''}  ·  ⏰ ${p.kickoff || ''}`,

    `\n🎯 *PICK RECOMENDADO:*`,
    `🔹 *Mercado:* ${mercadoEs}`,
    `✅ *Selección:* ${seleccionEs}`,
    `💰 *Cuota:* ${cuota.toFixed(2)} _(Bet365)_`,

    `\n📉 *ANÁLISIS CUANTITATIVO:*`,
    `· Prob. estimada: *${(parseFloat(p.prob_estimada || 0) * 100).toFixed(1)}%*`,
    `· Valor Esperado (EV): *+${(parseFloat(p.ev || 0) * 100).toFixed(1)}%*`,
    `· Confianza: *${numConfianza}%*`,
    `  [${bar}]`,
    `· Stake sugerido: ${stars} *${numStake}/5*`,

    `\n💡 *RAZONAMIENTO:*`,
    `${p.razonamiento || 'Sin razonamiento disponible.'}`,

    `\n🔘 *ESTADÍSTICAS DE EQUIPOS:*`,
    `🏠 *Local:* Pos ${l.posicion || l.pos || '-'} | ${l.puntos || l.pts || 0} pts`,
    `   Récord: ${l.pj || 0}pj (${l.pg || 0}V-${l.pe || 0}E-${l.pp || 0}D)`,
    `\n🚀 *Visitante:* Pos ${v.posicion || v.pos || '-'} | ${v.puntos || v.pts || 0} pts`,
    `   Récord: ${v.pj || 0}pj (${v.pg || 0}V-${v.pe || 0}E-${v.pp || 0}D)`,

    `\n🔥 *Score de Interés:* ${p.interest_score || p.score_interes || p.score || 0}/100`
].join('\n');

return { json: { ...p, telegram_text: msg } };

// ⚡ Modo Fórmula 1: Directo y sin nodos externos
return $input.all().map((item) => {
  const p = item.json;

  // 🛡️ Extraemos los logos directamente de los objetos home_stats y away_stats
  // Usamos corchetes ["..."] porque los nombres tienen espacios
  const homeLogo = p.home_stats?.["Logo Equipo"] || "";
  const awayLogo = p.away_stats?.["Logo Equipo"] || "";
  const leagueLogo = p.home_stats?.["Logo Liga"] || "";

  return {
    json: {
      sport: 'football',
      competition: p.competition || p.league || '-',
      match: p.match || (p.home + " vs " + p.away),
      market: p.market || p.mercado,
      pick: p.pick || p.seleccion,
      odds: parseFloat(p.odds || p.cuota_objetivo || 0),
      stake: parseInt(p.stake) || 1,
      match_date: p.date,
      razonamiento: p.razonamiento || '',
      confianza: parseInt(p.confianza) || 85,

      // Asignamos las URLs finales
      home_logo: homeLogo,
      away_logo: awayLogo,
      league_logo: leagueLogo,

      home_stats: p.home_stats || {},
      away_stats: p.away_stats || {},
      status: 'pending'
    }
  };
});

const items = $input.all();

const LIGAS_TOP = [
  'spain-laliga', 'england-premier-league', 'italy-serie-a', 
  'germany-bundesliga', 'france-ligue-1', 'usa-mls', 'brazil-serie-a'
];

// 1. Filtramos
const filtrados = items.filter(i => 
  LIGAS_TOP.includes(i.json.league?.slug) && 
  i.json.status !== 'cancelled'
).slice(0, 40); // Tomamos los mejores 40

// 2. Función para dividir en grupos de 10
const chunkArray = (arr, size) => {
  const chunks = [];
  for (let i = 0; i < arr.length; i += size) {
    chunks.push(arr.slice(i, i + size));
  }
  return chunks;
};

const lotesDe10 = chunkArray(filtrados, 10);

// 3. Devolvemos un ITEM por cada LOTE
// Esto hará que el siguiente nodo (HTTP) se ejecute 1 vez por cada lote
return lotesDe10.map(lote => {
  return {
    json: {
      eventIds: lote.map(p => p.json.id).join(','),
      partidos_en_este_lote: lote.length
    }
  };
});

const data = $json;
const b365 = data.bookmakers?.Bet365 || [];

// ✅ LISTA BLANCA PROFESIONAL
const whitelist = [
    'ML', 'Both Teams To Score', 'Totals', 'Spread', 
    'Double Chance', 'Draw No Bet', 'Corners', 
    'Half Time', 'Result/Both Teams To Score'
];

const allMarketsSummary = b365
    .filter(m => whitelist.some(word => m.name.includes(word))) 
    .map(market => {
        const oddsInfo = market.odds.map(o => {
            const parts = [];
            // Si hay hándicap o etiqueta, los ponemos primero
            if (o.hdp) parts.push(`(Hdp ${o.hdp})`);
            if (o.label) parts.push(`${o.label}:`);

            // Buscamos todas las claves de cuotas posibles en el objeto
            const keys = ['home', 'draw', 'away', 'yes', 'no', 'over', 'under', 'price'];
            keys.forEach(key => {
                if (o[key] && o[key] !== 'N/A') {
                    // Si el label ya existe (como en Doble Oportunidad), no repetimos la clave
                    const prefix = o.label ? '' : `${key.toUpperCase()}:`;
                    parts.push(`${prefix}${o[key]}`);
                }
            });
            return parts.join(' ');
        }).join(' | ');

        return `[${market.name}]: ${oddsInfo}`;
    }).join('\n');

const getOdds = (name) => b365.find(m => m.name === name)?.odds?.[0] || {};
const ml = getOdds('ML');
const btts = getOdds('Both Teams To Score');

return {
    home: data.home,
    away: data.away,
    match: `${data.home} vs ${data.away}`,
    league: data.league?.name || "Liga",
    competition: data.league?.name || "Fútbol", 
    date: data.date,
    kickoff: data.date ? new Date(data.date).toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' }) : "-",
    main_odds: {
        home: parseFloat(ml.home || ml.price) || 0,
        draw: parseFloat(ml.draw || ml.price) || 0,
        away: parseFloat(ml.away || ml.price) || 0,
        btts_yes: parseFloat(btts.yes || btts.price) || 0
    },
    full_market_dump: allMarketsSummary,
    home_logo: "https://via.placeholder.com/64?text=Home",
    away_logo: "https://via.placeholder.com/64?text=Away",
    league_logo: "https://via.placeholder.com/64?text=League"
};

// Convertimos los 200 items en 1 SOLO item que contiene la lista
return {
  json: {
    excel_data: $input.all().map(item => item.json)
  }
};
